"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[6497],{3391(e,n,t){t.r(n),t.d(n,{assets:()=>r,contentTitle:()=>s,default:()=>c,frontMatter:()=>o,metadata:()=>h,toc:()=>d});var i=t(4848),a=t(8453);const o={},s="Chapter 1: The Least Worst Choice",h={id:"mirror-realm/ch01",title:"Chapter 1: The Least Worst Choice",description:"Taiwan Edition v4",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/mirror-realm/ch01.md",sourceDirName:"mirror-realm",slug:"/mirror-realm/ch01",permalink:"/MythogenEngine/en/docs/mirror-realm/ch01",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Prologue: The Way of Disappearing",permalink:"/MythogenEngine/en/docs/mirror-realm/prologue"},next:{title:"Chapter 2: Welcome to Mist Valley",permalink:"/MythogenEngine/en/docs/mirror-realm/ch02"}},r={},d=[{value:"Taiwan Edition v4",id:"taiwan-edition-v4",level:3}];function l(e){const n={em:"em",h1:"h1",h3:"h3",header:"header",hr:"hr",p:"p",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"chapter-1-the-least-worst-choice",children:"Chapter 1: The Least Worst Choice"})}),"\n",(0,i.jsx)(n.h3,{id:"taiwan-edition-v4",children:"Taiwan Edition v4"}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Location: Mirror Realm - Intermediary Island Study (Parallel Universe No. 15)\nTime: JAN 1021 (5 years ago)\nProtagonist: Lin Zhao-ming"}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming was unemployed."}),"\n",(0,i.jsx)(n.p,{children:"He sat in the study. On the desk was a cup of cold tea, the screen was lit, and there were over ninety emails from headhunters in his inbox. He didn't open them. Not out of laziness, but because he knew exactly what was inside."}),"\n",(0,i.jsx)(n.p,{children:"The outside world was undergoing a massive reshuffling. Trade wars, pandemics, politics. Places that used to be viable options were closing their doors one by one; calculations that used to add up no longer made sense."}),"\n",(0,i.jsx)(n.p,{children:"It wasn't that he couldn't stay on Intermediary Island; it was that he didn't want to watch it turn into something else."}),"\n",(0,i.jsx)(n.p,{children:"He wasn't at a dead end. He had an apartment on Intermediary Island. Sell it, cash out, and he'd have enough money. The problem wasn't a lack of money; it was a lack of position. The entire layout of Asia was being redrawn, and his specific square just happened to be on the fault line."}),"\n",(0,i.jsx)(n.p,{children:"There was a reason pointing to Emerald Isle, one that had been there all along."}),"\n",(0,i.jsx)(n.p,{children:"Mist Valley had a unit he bought years ago, which he had been renting out. His aunt had passed away, and there were inheritance matters that needed someone to handle. He was the only one with the time to go. And then he lost his job. And then the outside world began that massive reshuffling."}),"\n",(0,i.jsx)(n.p,{children:'"Having to go once" turned into "Maybe I can stay."'}),"\n",(0,i.jsx)(n.p,{children:'There was a company recruiting him. Their official website was in English, stating "American-backed management." It looked like a normal foreign enterprise.'}),"\n",(0,i.jsx)(n.p,{children:'"Looked like a normal foreign enterprise."'}),"\n",(0,i.jsx)(n.p,{children:"He stared at this line of text and paused for a moment."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"The interview consisted of two rounds via video call."}),"\n",(0,i.jsx)(n.p,{children:"The first round was with HR. Mandarin, American accent, asking standard questions. Lin Zhao-ming gave the standard answers. Formula meeting formula\u2014everyone knew how to play the game."}),"\n",(0,i.jsx)(n.p,{children:"The second round was with the entire Team\u2014over a dozen people: senior manager, director, principal engineer, senior principal engineer, all lined up. There were technical questions, but they lacked depth. He could only give what he thought was the best answer. Then the topic shifted: What is your weakness? What was your worst work experience? How did you overcome it?"}),"\n",(0,i.jsx)(n.p,{children:"Interviews at an American company weren't supposed to be like this. In the US, technical assessments tested how you think, how you react under uncertainty, pushing until you couldn't answer to find your boundaries. Not here. Here, they were testing if you could recite from textbooks\u2014management textbooks, human resources textbooks, \"Modern Workplace Leadership\" textbooks."}),"\n",(0,i.jsx)(n.p,{children:"To formulaic questions, he gave formulaic answers. The other side nodded."}),"\n",(0,i.jsx)(n.p,{children:"After the interview, he sat in the study for a while."}),"\n",(0,i.jsx)(n.p,{children:"He thought he was going to get an authentic American burger made with fresh beef. Even a chain fast-food burger would have been fine; at least you knew what you were getting, no surprises. But what he was handed was a Gua Bao stuffed with a canned burger patty, served on a plate with an English menu."}),"\n",(0,i.jsx)(n.p,{children:"He didn't back out."}),"\n",(0,i.jsx)(n.p,{children:"There was a calculation he didn't voice aloud: The company had already implemented WFH before the pandemic. The entire interview was via video. He could do the job from Intermediary Island. Even if there were problems after joining, with a WFH job, changing the location where he collected his salary, or changing his tax residency, shouldn't theoretically be too hard. He had done this before\u2014collecting a salary on Intermediary Island while working in mainland China. This logic gave him a feeling: Even if it wasn't a good fit, it wouldn't be a dead end."}),"\n",(0,i.jsx)(n.p,{children:"The offer came. He signed it."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"The five years he worked at the American company were the most comfortable time of his career."}),"\n",(0,i.jsx)(n.p,{children:"The boss was an American in his thirties, a newcomer taking over the family business. Straightforward, direct. If you did an excellent job, you had a place; if you messed up, he told you directly. No beating around the bush, no talk of \"this is a growth opportunity.\" He learned one thing there: Technology is a language. If your language is good enough, that's enough; you don't need anything else."}),"\n",(0,i.jsx)(n.p,{children:"He was used to focusing on results, not used to protecting himself. Just make a good bowl of noodles, and that's it. As for the rest\u2014whether he understood the unspoken rules, whether he knew how to call people by those specific titles\u2014he thought it didn't matter."}),"\n",(0,i.jsx)(n.p,{children:"Then things happened on the outside. The pandemic, politics, and the business decided to relocate to the Harmony Sphere. The boss called. We spoke a few sentences, his tone flat\u2014it wasn't bad news, just that the environment had changed. No one was right, no one was wrong."}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming listened, without speaking."}),"\n",(0,i.jsx)(n.p,{children:'The boss also knew he wouldn\'t go. His wife was from Emerald Isle, the children were still young, their home was there. These things didn\'t need explaining; saying them out loud would only make it weird. Both of them understood, so no one said "what a pity," no one said "I\'m sorry." And that was that.'}),"\n",(0,i.jsx)(n.p,{children:"Fifteen months of severance pay, wired directly into his account. No bullshit, no strings attached, no asking him to sign anything."}),"\n",(0,i.jsx)(n.p,{children:"After hanging up the phone, he sat in his study."}),"\n",(0,i.jsx)(n.p,{children:"Before the American company, he had worked at PG. That was a different kind of affair\u2014an old-style Chinese-funded enterprise on Intermediary Island that ultimately went into sell-off mode. Someone asked him to cook the books. He refused, lost some connections, but could sleep at night."}),"\n",(0,i.jsx)(n.p,{children:'The American company was the closest thing to "normal" he had ever seen. Normal meant: what you did, was what you did. When it was over, it was over. No rhetorical traps, no extraneous bullshit.'}),"\n",(0,i.jsx)(n.p,{children:'He brought this standard of "normal" with him to Emerald Isle.'}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"He had worked at headquarters, and he had worked at the Asian hub. He had been dispatched to Emerald Isle a few years ago to implement policy\u2014the headquarters had a direction, and he was responsible for landing it. At that time, he could see how policies trickled from the top down, but he couldn't see the obstacles hidden beneath the table. He thought the failure of the transformation was a market problem, an execution problem."}),"\n",(0,i.jsx)(n.p,{children:"This time was different. This was his first time joining as a local regional employee."}),"\n",(0,i.jsx)(n.p,{children:"People used to tell him that regional roles were relaxed\u2014support-in-nature, no frontline pressure, just follow the headquarters. It wasn't that he didn't believe it; he just never thought to question it."}),"\n",(0,i.jsx)(n.p,{children:"In every job he took, he kept an eye on what was happening in the world. When robotics rose, he studied it. When AI arrived, he studied it too. Anything fun and interesting, he would try it out. This habit gave him a feeling: Even if this place didn't work out, the world was so big, there was always somewhere else to go."}),"\n",(0,i.jsx)(n.p,{children:'He thought of a question, but had no answer: If this choice is right, what is the standard for being "right"?'}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"He signed his name on the electronic contract, clicked confirm, and closed his laptop."}),"\n",(0,i.jsx)(n.p,{children:"Then he sat in the study for a long time, doing nothing."}),"\n",(0,i.jsx)(n.p,{children:"Outside the window was the night of Intermediary Island. A few apartments in the building opposite still had their lights on. In the distance was the harbor, the lights flickering intermittently on the water."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"That night, he called his wife over to sit down."}),"\n",(0,i.jsx)(n.p,{children:'"I accepted an offer. To Emerald Isle. A tech company with an American background."'}),"\n",(0,i.jsx)(n.p,{children:"She looked at him and didn't answer immediately. Then she said, \"Okay, let's go then.\""}),"\n",(0,i.jsx)(n.p,{children:"She didn't ask him if he was sure. And he didn't tell her how unsure he was."}),"\n",(0,i.jsx)(n.p,{children:"That was the first conversation they never finished. There would be many more later."}),"\n",(0,i.jsx)(n.p,{children:"The lights went out. The night on Intermediary Island was quiet."}),"\n",(0,i.jsx)(n.p,{children:"The initial calculation had been very simple."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"It wasn't that I chose this job. It was that after doing the math, I picked the least worst answer. And then the system told you: You chose wrong, and it's your problem."})})]})}function c(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(l,{...e})}):l(e)}},8453(e,n,t){t.d(n,{R:()=>s,x:()=>h});var i=t(6540);const a={},o=i.createContext(a);function s(e){const n=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function h(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);